1	import { existsSync, readFileSync, rmSync, writeFileSync } from "node:fs";
2	import { join } from "node:path";
3	import { app, safeStorage } from "electron";
4	import { z } from "zod";
5	
6	const persistedSchema = z.object({
7	  token: z.string().min(1),
8	  savedAt: z.number().int().positive(),
9	});
10	type Persisted = z.infer<typeof persistedSchema>;
11	
12	export interface AuthSnapshot {
13	  isSignedIn: boolean;
14	}
15	
16	let memory: string | null = null;
17	const listeners = new Set<(snapshot: AuthSnapshot) => void>();
18	
19	function storePath(): string {
20	  return join(app.getPath("userData"), "auth.bin");
21	}
22	
23	function load(): string | null {
24	  if (memory) {
25	    return memory;
26	  }
27	  const path = storePath();
28	  if (!existsSync(path)) {
29	    return null;
30	  }
31	  if (!safeStorage.isEncryptionAvailable()) {
32	    return null;
33	  }
34	  try {
35	    const buf = readFileSync(path);
36	    const plain = safeStorage.decryptString(buf);
37	    const parsed = persistedSchema.safeParse(JSON.parse(plain));
38	    if (!parsed.success) {
39	      console.error("[auth-store] invalid persisted payload", parsed.error);
40	      return null;
41	    }
42	    memory = parsed.data.token;
43	    return memory;
44	  } catch (err) {
45	    console.error("[auth-store] failed to load", err);
46	    return null;
47	  }
48	}
49	
50	function persist(token: string): void {
51	  memory = token;
52	  if (!safeStorage.isEncryptionAvailable()) {
53	    console.error(
54	      "[auth-store] safeStorage unavailable; refusing to write plaintext"
55	    );
56	    return;
57	  }
58	  try {
59	    const payload: Persisted = { token, savedAt: Date.now() };
60	    const buf = safeStorage.encryptString(JSON.stringify(payload));
61	    writeFileSync(storePath(), buf);
62	  } catch (err) {
63	    console.error("[auth-store] failed to persist", err);
64	  }
65	}
66	
67	function clearPersisted(): void {
68	  memory = null;
69	  try {
70	    rmSync(storePath(), { force: true });
71	  } catch (err) {
72	    console.error("[auth-store] failed to remove", err);
73	  }
74	}
75	
76	function emit(): void {
77	  const snapshot: AuthSnapshot = { isSignedIn: memory !== null };
78	  for (const listener of listeners) {
79	    listener(snapshot);
80	  }
81	}
82	
83	export function getAuthSnapshot(): AuthSnapshot {
